#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int prices[26];
        for (int i = 0; i < 26; i++) {
            scanf("%d", &prices[i]);
        }
        char text[50001];
        scanf("%s", text);
        int freq[26] = {0};
        for (int i = 0; i < strlen(text); i++) {
            freq[text[i] - 'a']++;
        }
        int cost = 0;
        for (int i = 0; i < 26; i++) {
            if (freq[i] == 0) {
                cost += prices[i];
            }
        }
        printf("%d\n", cost);
    }
    return 0;
}

