import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int[] prices = new int[26];
            for (int i = 0; i < 26; i++) {
                prices[i] = sc.nextInt();
            }
            String text = sc.next();
            int[] freq = new int[26];
            for (int i = 0; i < text.length(); i++) {
                freq[text.charAt(i) - 'a']++;
            }
            int cost = 0;
            for (int i = 0; i < 26; i++) {
                if (freq[i] == 0) {
                    cost += prices[i];
                }
            }
            System.out.println(cost);
        }
    }
}

