        freq[text.charCodeAt(j) - 'a'.charCodeAt(0)]++;
    }
    let cost = 0;
    for (let j = 0; j < 26; j++) {
        if (freq[j] === 0) {
            cost += prices[j];
        }
    }
    console.log(cost);
}
